INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (20001, 0, "", 0, 10, "", 2, 320, 20, 0, 23001);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 125801, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, 1, "リリ", 2, 321, 1, 0, 24001);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 126001, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 1, 2, "クリア", 2, 322, 1, 0, 24001);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 126101, "んーと。\nこれ、あげる。\nはい", 1, 3, "プレシア", 2, 323, 1, 0, 24001);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 125801, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 2, 4, "リリ", 2, 324, 1, 0, 24001);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 126001, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 2, 5, "クリア", 2, 325, 1, 0, 24001);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (40011, 126101, "お兄。\nきてくれて、うれしい", 2, 6, "プレシア", 2, 326, 1, 0, 24001);
INSERT INTO `v1_35fea868b381ff3e92e98dedfbe0aef2543d365fb8abc57ac66b0a5d7f0afc2d` VALUES (80009, 0, "", 0, 1, "", 8, 327, 100, 532001, 91002);
